var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"마을의 상황은 어떻지?","JPN":"村の状況はどうだ？","ENG":"What's the situation in the village?","TWN":"村子的情況怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"온통 침식체들 뿐입니다. 발견된 주민들은 이미 모두 사망했습니다.","JPN":"侵食体しかいません。発見された住民は全員死亡しました。","ENG":"It's swarming with C.O.s. All the civilians are dead.","TWN":"全是侵蝕體。目前發現的村民都已經死亡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"수색 범위를 확대하도록. 아직 생존자가 있을 지도 모른다.","JPN":"捜索範囲を拡大するように。まだ生存者がいるかもしれない。","ENG":"Expand the search. There may still be survivors.","TWN":"擴大搜索範圍，或許還有倖存者。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저긴...... 버려진 교회인가?","JPN":"あれは……放棄された教会か？","ENG":"Is that... an abandoned church?","TWN":"那裡是……被遺棄的教會嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"꺄아아악!","JPN":"きゃあああ！","ENG":"Aaaaaaaagh!","TWN":"呃啊啊阿！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"으윽...... 괴물 놈들......","JPN":"うぅ……化け物め……","ENG":"Ugh... You monsters...","TWN":"呃……怪物們……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"웃기지 마, 내가...... 이대로 죽을 것 같아?","JPN":"ふざけるな、私は……こんなところでは死なない！","ENG":"Don’t make me laugh... You think I'll die like this?","TWN":"別開玩笑了，以為我會……就這麼死嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"괜찮은가? 꼬마.","JPN":"大丈夫か、チビ。","ENG":"You alright, kid?","TWN":"你沒事吧？小朋友。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L24_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......당신, 누구야?","JPN":"……あなたは、誰？","ENG":"Who are you?","TWN":"……你，是誰？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"다, 다가오지 마!","JPN":"ち、近寄るな！","ENG":"S-stay away!","TWN":"別、別過來！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"경계심이 좋은 꼬마로군. 하지만 쓸데없는 짓이다.","JPN":"警戒心があるのはいいことだ。だが今は必要ない。","ENG":"Relax kid, relax. Don't worry, we're not here to harm you.","TWN":"看來是個很有警戒心的小鬼啊。不過別掙扎了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"우린 민간인들을 구출하러 온 구원부대다.","JPN":"私たちは民間人を助けにきた救助部隊だ。","ENG":"We're a rescue unit, here to evacuate civilians.","TWN":"我們是來營救平民的救援部隊。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"귀찮게 반항할 필요는 없어...... 음?","JPN":"抵抗する必要は……うむ？","ENG":"You don't have to resist—hmm?","TWN":"沒必要反抗造成麻煩……嗯？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"이, 이 손 놔!","JPN":"は、放してよ！","ENG":"L-let go!","TWN":"放開我的手！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 피부는...... 침식 증상이로군.","JPN":"この皮膚は……侵食症状か。","ENG":"The lesions on your skin... They are the symptom of Corruption Syndrome.","TWN":"這皮膚……是侵蝕症狀。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 이 정도의 침식 증후군이라면 벌써 이성을 잃었을 텐데 어떻게......?","JPN":"しかしこれほどの侵食症候群ならとっくに理性を失うはずだが、どうやって……？","ENG":"But at this stage of the Syndrome... You should have lost your mind by now. How...","TWN":"可如果是這種程度的侵蝕症候群，應該早就喪失理智了才對，她……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"손 대면 안 된다고, 바보! 병이 옮을지도 모른단 말이야!","JPN":"触んないでってば、バカ！　病気が移ったらどうするんだよ！","ENG":"Don't touch me, stupid! You might get contaminated!","TWN":"不要碰，蠢貨！搞不好會被傳染！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니, 이 정도의 침식으로는 내 피부를 뚫을 수 없다.","JPN":"いや、この程度の侵食で私には影響はない。","ENG":"No, Corruption at this level can't penetrate my skin.","TWN":"不，這種程度的侵蝕，沒辦法穿透我的皮膚。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"어찌된 일인지는 모르겠지만 치료를 해 보면 알게 되겠지.","JPN":"理由は不明だが、治療をすればわかるだろう。","ENG":"I don't know how this happened, but we'll find out after we get you treatment.","TWN":"雖然不知道是怎麼回事，去治療之後應該就清楚了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"본부! 생존자를 발견했다. 상태가 위중하니, 즉시 수술을 준비하도록.","JPN":"本部！　生存者を発見した。症状が重いので、ただちに手術の準備をするように。","ENG":"HQ! We found a survivor. She's in critical condition, so prep for surgery immediately.","TWN":"總部！發現生存者。狀態危急，需要立即準備手術。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......치료?","JPN":"……治療？","ENG":"Treatment?","TWN":"……治療？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"설마 날...... 도와주는 거야?","JPN":"もしかして私を……助けてくれるの？","ENG":"Are you... going to help me?","TWN":"難道……是要幫我嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그래. 그것이 내 의무들 중 하나니까.","JPN":"そうだ。それが私の義務の一つだからな。","ENG":"Yes. That's one of my duties.","TWN":"是啊。因為這是我的義務之一。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"꼬마, 이름이 뭐지?","JPN":"チビ、名前は？","ENG":"Kid, what’s your name?","TWN":"小鬼，你叫什麼名字？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"......제이나.","JPN":"……ジェイナ。","ENG":"Jaina.","TWN":"……婕娜。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"제이나 크로펠이야.","JPN":"ジェイナ・クロペルだよ。","ENG":"Jaina Kropel.","TWN":"我叫婕娜·克洛佩爾。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"강해 보이는 이름이로군.","JPN":"強そうな名前だな。","ENG":"That's a strong name.","TWN":"聽起來是個很堅強的名字呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이젠 안전하니까, 걱정말고 쉬도록 해라. 제이나.","JPN":"もう安全だ。心配せず休むがいい、ジェイナ。","ENG":"You're safe now, Jaina. Don't worry, and get some rest.","TWN":"現在安全了，放心休息吧。婕娜。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"저 떠돌이 꼬마가 정말 마을로 들어온 괴물을 때려잡았다고?","JPN":"あの子どもが本当に村を襲った化け物を退治しただと？","ENG":"That little kid really defeated the monster that came into the village?","TWN":"你說那個流浪的小鬼真的消滅了入侵村子的怪物？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"네! 보세요! 아이의 상처가 순식간에 아물고 있어요. 이건 기적입니다.","JPN":"はい、見てください！　この子の傷が一瞬で治っています。これは奇跡です。","ENG":"Yes! Look! The child's wounds are healing in an instant. This is a miracle.","TWN":"對！你看！孩子的傷口正在瞬間癒合。這真是奇跡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"아아, 이 아이는 신께서 우리 마을에 내리신 축복이에요.","JPN":"ああ、この子は神様がこの村に与えた祝福です。","ENG":"Ah, this child is God's blessing on our village.","TWN":"啊啊，這個孩子是神賜給我們村子的祝福。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"넌 축복이자 우리의 희망이야, 제이나.","JPN":"君は祝福であり我々の希望なんだ、ジェイナ。","ENG":"You are our blessing and hope, Jaina.","TWN":"你是祝福，也是我們的希望，婕娜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"너만이 사특한 악마들로부터 우리 마을을 지켜줄 수 있단다.","JPN":"君だけが邪悪な悪魔から我が村を守ることができる。","ENG":"Only you can protect our village from wicked demons.","TWN":"只有你能保護村子不受邪惡的惡魔侵犯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"나는...... 축복......","JPN":"私は……祝福……","ENG":"I am... a blessing...","TWN":"我是…… 祝福……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"저 애가 원인인 게 틀림없어요!","JPN":"あの子のせいです！","ENG":"That child must be the cause!","TWN":"肯定是因為那個孩子！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"저 아이의 몸이 변하기 시작한 뒤로 사람들이 앓아 눕고 있다고요!","JPN":"あの子の身体が変わり始めてから、みんな病み始めたのです！","ENG":"People have fallen ill ever since her body began changing!","TWN":"那個孩子的身體開始變異後，人們就一個個病倒了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"피부 위로 돋아난 저 징그러운 돌기 좀 보세요!","JPN":"皮膚から浮き上がってきたあの気持ち悪い腫れ物を見てください！","ENG":"Look at those disgusting bumps on her skin!","TWN":"看看他皮膚上面那些隆起的噁心東西！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"저 아이도 곧 다른 괴물들처럼 변하고 말 겁니다. 괴물을 마을에 둘 순 없어요!","JPN":"あの子も間もなく、他の化け物のように変わってしまうでしょう。あんな化け物を村には置けません！","ENG":"She will soon turn into another monster. We can't keep her in the village!","TWN":"那孩子馬上就會變成像其他怪物那樣。不能把怪物留在村子裡！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"나는...... 괴물......","JPN":"私は……化け物……","ENG":"I am... a monster...","TWN":"我是…… 怪物……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"제이나, 앞으로는 여기서 지내도록 하렴.","JPN":"ジェイナ、これからはここで過ごしなさい。","ENG":"Jaina, stay here from now on.","TWN":"婕娜，以後你就住在這裡。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"어른들 허락도 없이 멋대로 마을로 돌아와서는 절대 안돼!","JPN":"大人の許可なく勝手に村に戻っては絶対にダメ！","ENG":"Never come back to the village without permission from grown-ups!","TWN":"沒有大人們的允許，絕對不可以擅自回到村子去！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"빨리 나와서 문부터 막아! 저 괴물 때문에 역병이 옮는다고!","JPN":"早く出てきて扉を封じろ！　あの化け物のせいで疫病が移るだろ！","ENG":"Get out of here and block the door! That monster will spread the plague!","TWN":"快出來把門堵住！那個怪物會傳染疫病！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"나는...... 뭐지......?","JPN":"私は……何者……？","ENG":"What... am I?","TWN":"我是…… 什麼……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_DELTA_NPC_NULL","text":{"KOREA":"......일반적인 카운터라면 진작에 그림자가 되고도 남았겠지만 조건이 좋았습니다.","JPN":"……一般的なカウンターならとっくにシャドウになっていたと思いますが、条件が良かったようです。","ENG":"If she was a normal Counter, she'd already be a Shadow. But these unique conditions have resulted in an unexpected outcome.","TWN":"……如果是普通制裁者的話，早就轉變成暗影了，只能說她的天賦很好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_DELTA_NPC_NULL","text":{"KOREA":"이 아이는 재생능력은 물론 조직의 내구도나 결속력이 압도적으로 뛰어나요.","JPN":"この子は再生能力はもちろん、組織の耐久度や結合力が非常に優れています。","ENG":"This child has superb regeneration abilities, as well as outstanding tissue durability and cohesion.","TWN":"這孩子不僅是再生能力，連組織的耐久度和穩定性也非常出色。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_DELTA_NPC_NULL","text":{"KOREA":"짧은 시간이라면 세포 단위로 분해했다가 재조립해도 거의 후유증이 없을 정도로요.","JPN":"短時間なら細胞単位で分解や再構成をしても、ほとんど後遺症が残らないほどです。","ENG":"She could be broken down to a cellular level and reassembled without any aftereffects, if it's only for a limited time.","TWN":"甚至短時間內以細胞單位分解後再進行重組，也不會留下後遺症。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_DELTA_NPC_NULL","text":{"KOREA":"덕분에 침식 증후군이 신체 내부로 깊이 침투하지 못한 것 같습니다.","JPN":"おかげで侵食症候群が体内に深く浸透しなかったようです。","ENG":"Thanks to these traits, Corruption has not fully taken over her body.","TWN":"好像也是得益於此，侵蝕症候群沒能深入侵透到身體內部。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_DELTA_NPC_NULL","text":{"KOREA":"이터니움을 꽤나 투입해야겠지만 생명에는 지장이 없을 겁니다.","JPN":"エタニウムを大量に投入しなければなりませんが、命に別状はないでしょう。","ENG":"We'll have to inject her with a large amount of Eternium, but she won't have to fear for her life.","TWN":"雖然需要投入很多永恆之金，但不會對她的生命造成影響。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"고맙군. 자네의 공적은 사령관님께도 잘 전해드리도록 하지.","JPN":"ご苦労だった。君の功績は司令官にもしっかり報告するとしよう。","ENG":"Thank you. I'll convey your accomplishments to the Commander.","TWN":"謝謝。你的功績我會好好傳達給司令官大人的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_DELTA_NPC_NULL","text":{"KOREA":"감사합니다! 레지날드 부사령관님!","JPN":"ありがとうございます！　レジナルド副司令官！","ENG":"Thank you! Deputy Commander Reginald!","TWN":"謝謝您！多明尼克副司令官大人！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"......으음.","JPN":"……うぅん。","ENG":"Ngh...","TWN":"唔……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"깨어났나?","JPN":"目が覚めたか？","ENG":"You awake?","TWN":"你醒了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"신기해. 이제 아프지 않아.","JPN":"なんか不思議。もう痛くない。","ENG":"Strange. It doesn't hurt anymore.","TWN":"真是神奇，現在不疼了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"치료는 성공적으로 마쳤다. 네가 지금까지 포기하지 않고 잘 견뎌낸 덕분이지.","JPN":"治療は成功した。お前がこれまで諦めず、よく耐えてきたおかげだ。","ENG":"The treatment was successful because you didn't give up and endured it well so far.","TWN":"治療非常成功。也多虧你自己能堅持到現在，沒有放棄。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 카운터는 능력을 사용하려면 이터니움이 필요하다.","JPN":"しかし、カウンターは能力を使うために、エタニウムが必要だ。","ENG":"But Counters need Eternium to use their abilities.","TWN":"但制裁者使用能力時，需要消耗永恆之金。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그렇지 않으면 그림자가 되고 말아.","JPN":"そうしないとシャドウになってしまう。","ENG":"Otherwise, they become Shadows.","TWN":"不那樣的話，就會變成暗影。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내게 퇴치 당하는 신세가 되기 싫다면 다음부턴 잘 숙지해 두도록.","JPN":"私に退治される羽目になりたくなければ、これからはその事実を常に意識するように。","ENG":"If you don't want to be exterminated, keep that in mind from now on.","TWN":"如果你不想以後被我消滅的話，下次最好記住。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 퇴원 후, 네 신변은 캄파멘토 임시 구호소에 양도될 거다.","JPN":"そして退院後のお前の身元は、カンパメント臨時救護所が引き受けることになった。","ENG":"And after you leave the hospital, you'll be transferred to a temporary shelter in Campamento.","TWN":"還有出院後，你的監護權會被轉移給坎帕門托臨時救護所。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"고향이 어디인진 모르겠지만, 그곳에서 잘 적응하며 지내길 바라지.","JPN":"出身がどこなのかわからないが、そこで無事に過ごせることを願う。","ENG":"I don't know where you're from, but I hope you get used to your new home.","TWN":"雖然不知道你的故鄉是哪，但我希望你能適應新地方好好生活。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"나는 이제 부대로 복귀를 해야 하니, 이 손은 놓아주지 않겠나?","JPN":"私はそろそろ部隊に復帰しなければならない。この手は放してくれないか？","ENG":"I have to return to my unit, so could you please let go of my hand?","TWN":"我現在必須回部隊了，你能把我的手放開嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"......가지마.","JPN":"……行かないで。","ENG":"...Don't go.","TWN":"……別走。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"여기 혼자 있기 싫어.","JPN":"ここで一人になりたくない。","ENG":"I don't want to be here alone.","TWN":"我不想一個人待在這裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"이제...... 아무도 믿고 싶지 않아.","JPN":"もう……誰も信じたくない。","ENG":"I don't want to trust anyone anymore...","TWN":"現在…… 我不相信任何人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"따라가게 해줘.","JPN":"連れていって。","ENG":"Please let me follow you.","TWN":"我想跟你走。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......아무도 믿지 못한다면서, 이름도 모르는 날 어떻게 믿겠다는 거지?","JPN":"……誰も信じられないと言いながら、名前も知らない私をどう信じるというんだ？","ENG":"You just said you can't trust anyone. How can you trust me when you don't even know my name?","TWN":"……既然不相信任何人，你連我的名字都不知道，為什麼要相信我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"레지날드.","JPN":"レジナルド。","ENG":"Reginald.","TWN":"多明尼克。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"아까 그 남자가 말하는 걸 들었어.","JPN":"さっきの男の人がそう呼んでいた。","ENG":"I heard that man say it.","TWN":"我剛才聽到那個男人說了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"난 군인이다. 그리고 널 구해줄 때 말했듯이 내겐 의무가 있어.","JPN":"私は軍人だ。そしてお前を助けた時にも言ったが、私には義務がある。","ENG":"I'm a soldier. And like I said when I rescued you, I have duties to fulfill.","TWN":"我是軍人。還有救你的時候我說過，我有我的義務。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그러니 내게 널 챙기고 돌봐 줄 여유는 없다.","JPN":"だから私にお前の面倒を見る余裕などない。","ENG":"I can't afford to take care of you.","TWN":"所以沒空照顧你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"그럼...... 나도 군인이 될게.","JPN":"それじゃあ……私も軍人になる。","ENG":"Then... I'll become a soldier, too.","TWN":"那…… 我也要成為軍人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"돌봐주지 않아도 돼. 난 괴물도 죽일 수 있어.","JPN":"面倒は見てくれなくていい。私は化け物も殺せる。","ENG":"You don't have to take care of me. I can kill monsters.","TWN":"不用照顧我。我連那些怪物都能自己搞定的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"분명 쓸모가 있을 테니까...... 데려가줘.","JPN":"きっと使い道があるから……連れていって。","ENG":"I'll be of use... Please take me with you.","TWN":"我一定會你對有用處的……帶我走吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......재미있는 꼬마로군.","JPN":"……面白いチビだな。","ENG":"You're a funny kid.","TWN":"……真是個有趣的小鬼啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"그냥...... 가는 거야?","JPN":"そのまま……行っちゃうの？","ENG":"You're... just leaving?","TWN":"你…… 你要走了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"그 사람들이 그랬던 것처럼...... 날...... 버리는 거야?","JPN":"あの人たちみたいに……私を……捨てるの？","ENG":"You're abandoning me... just like they did?","TWN":"你也會和以前那些人一樣…… 拋棄…… 我嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"걱정마라. 군인은 전우를 버리지 않는다.","JPN":"心配するな。軍人は、戦友を見捨てない。","ENG":"Don't worry. Soldiers never abandon their comrades.","TWN":"別擔心，軍人不會拋棄戰友。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"전우? 그렇다는 건......","JPN":"戦友？　ということは……","ENG":"Comrades? You mean...","TWN":"戰友？那就是說……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"카운터 능력자라면 연령이 낮아도 임시 모병이 가능하다는 상부의 훈령이 있었다.","JPN":"カウンター能力者であれば、年齢が低くても臨時募兵が可能という上部の訓令があった。","ENG":"We were given instructions that Counters are eligible for recruitment, even if they are young.","TWN":"根據上級訓令，如果是制裁者，即使年齡小也可以臨時招募。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"물론 부대 사령관의 허락이 있어야 하지만...... 그건 내가 어떻게 해볼 수 있을 것 같군.","JPN":"もちろん部隊司令官の許可は必要だが……それは私がどうにかできそうだ。","ENG":"Of course, it requires the Commander's approval, but I think I can handle that.","TWN":"當然，需要先得到部隊司令官的同意……我想這個我可以解決。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"안토노프 사령관님은 너 같은 어린아이가 싸우는 걸 별로 좋아하진 않으시겠지만......","JPN":"アントノフ司令官はお前みたいな子どもが戦うのを快く思わない方ではあるが……","ENG":"Commander Antonov won't like the idea of a child fighting in the battlefield...","TWN":"雖然安東諾夫司令官大人不喜歡看到像你這樣的小孩子參加戰鬥……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이런 시기에 홀로 남은 꼬마가 구호소에 가는 것도 안전하지만은 않으니까.","JPN":"このような時期に一人残された子どもが救護所に行くのも安全とは言えないだろう。","ENG":"But it's not exactly safe for a lone child to stay at a shelter in times like these.","TWN":"但現在的時機，讓小孩子一個人去救護所也不是很安全。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"앞으로는 날 부사령관님이라고 부르고 예의를 갖추도록.","JPN":"これからは私を副司令官と呼び、礼儀をわきまえるように。","ENG":"From now on, call me Deputy Commander and show me respect.","TWN":"以後你需要叫我副司令官大人，得遵守禮儀。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 아쉽게도 당분간 괴물을 죽일 일은 없을 거야.","JPN":"しかし残念ながら、当分化け物を殺すことはないだろう。","ENG":"You won't have the chance to kill monsters for a while.","TWN":"還有雖然有些遺憾，但暫時不需要殺怪物。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"진정한 군인이 되려면 기초적인 훈련과 교육부터 받아야 할 테니까.","JPN":"一人前の軍人になるためには、先に基礎訓練と教育を受ける必要がある。","ENG":"To become a true soldier, you need basic training and education first.","TWN":"因為想成為真正的軍人，需要先完成基礎訓練和教育。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"......응, 아, 아니. 열심히 배우겠습니다.","JPN":"……うん、いや、はい、一生懸命勉強します。","ENG":"Okay. I-I mean... Yes, sir, I'll do my best.","TWN":"……嗯，啊，不。我會認真學習的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAINA_KID_NPC_NULL","text":{"KOREA":"레지날드 부사령관님.","JPN":"レジナルド副司令官。","ENG":"Deputy Commander Reginald.","TWN":"多明尼克副司令官大人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"퇴원날이 되면 데리러 오겠다.","JPN":"退院日になったら迎えに来る。","ENG":"I'll pick you up on the day you're discharged.","TWN":"等到了出院的日子，我會來接你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......제이나.","JPN":"……ジェイナ。","ENG":"...Jaina.","TWN":"……婕娜。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"신호가 가까워졌군.","JPN":"シグナルが近くなった。","ENG":"The signals are near.","TWN":"信號越來越近了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"휴대용 침식파 레이더의 반응에 따르면 네임리스 원의 유해는...... 바로 저기다.","JPN":"携帯用侵食波レーダーの反応によるとネームレスワンの遺骸は……あそこか。","ENG":"According to the portable radar, the remains of the Nameless One are located... over there.","TWN":"根據可攜式侵蝕波雷達的反應，無名1的遺骸……就在那邊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_GRAVE_START_01"},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저건...... 대체 뭐지?","JPN":"あれは……いったい何だ？","ENG":"What's that thing?","TWN":"那個……究竟是什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저건 마치...... 거대한 고치처럼 보이는데.","JPN":"まるで……巨大な繭に見えるな。","ENG":"It looks like a huge cocoon.","TWN":"就像個……巨大的卵囊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이곳에 떨어진 네임리스 원이 저 고치로 변화한 건가? 어째서?","JPN":"ここに落ちたネームレスワンがあの繭に変化したのか？　なぜ？","ENG":"Did the Nameless One fall here and turn into that cocoon? Why?","TWN":"是墜落在這裡的無名1變成的卵囊嗎？怎麼會？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......내가 고민해봐야 답이 나올 문제는 아니로군.","JPN":"……私が考えても答えが出そうな問題ではないか。","ENG":"It's not a matter for me to speculate upon.","TWN":"……估計我想破腦袋也找不到答案。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"놈의 유해를 수거해서 분석하면 알게 될 일이다.","JPN":"奴の遺骸を回収して分析すればいい。","ENG":"We'll know when we collect and analyze its remains.","TWN":"將它的遺骸回收，進行分析後就都清楚了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"귀찮은 놈들이 여기에도 몰려있었군.","JPN":"厄介な奴らがここにも群がっていたか。","ENG":"There's another bunch of creatures here.","TWN":"這裡也有好多麻煩的傢伙聚在一起。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런데 저 놈들, 네임리스 원의 유해를 뜯어먹고 있는 건가?","JPN":"あいつら、ネームレスワンの遺骸を食べているのか？","ENG":"Are they eating the Nameless One's remains?","TWN":"但這些傢伙，是在吃無名1的遺骸嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"어쩌면 그래서 평범한 침식체보다 강력했던 것 같군.","JPN":"その影響で普通の侵食体よりも強力だったわけか。","ENG":"Maybe that's why they're stronger than normal C.O.s.","TWN":"可能就是因為這樣，才會比普通的侵蝕體強大吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그러고보니, 저 침식체 놈들 마치 제이나의 능력과 비슷한 특징을 가지고 있었어.","JPN":"そういえばあの侵食体も、ジェイナの能力に似た特徴を持っていたな。","ENG":"Now that I think about it, those C.O.s had traits similar to Jaina's.","TWN":"這樣來看，那些侵蝕體好像有與婕娜的能力類似的特徵。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설마?!","JPN":"まさか！？","ENG":"No, it can't be...","TWN":"難道？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부...... 사령관...... 님......","JPN":"副……司令……官……","ENG":"Deputy... Commander...","TWN":"副……司令……官大人……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_GRAVE_START_01"},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제이나?!","JPN":"ジェイナ！？","ENG":"Jaina?","TWN":"婕娜？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"정말로 아직 살아있었나?","JPN":"本当にまだ生きていたのか？","ENG":"You're really alive?","TWN":"你真的還活著？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"기다려라! 내가 구해주지!","JPN":"待っていろ。今すぐ助けてやる！","ENG":"Hang on! I'll rescue you!","TWN":"等著我！我來救你！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_RECRUITMNET_LIGHTNING"},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이번에는 절대 실수하지 않겠다!!","JPN":"今度こそ絶対に失敗しない！","ENG":"I won't fail this time!","TWN":"這次絕對不會失誤！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_RECRUITMNET_LIGHTNING"}]`);export{e as default};